function solve(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    const counts = {};
    const firstOccurrence = {};
    const vowelIndices = [];

    // Step 1: Analysis (Frequencies, First Occurrence, Indices)
    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            // Track frequency
            counts[char] = (counts[char] || 0) + 1;

            // Track first occurrence
            if (!(char in firstOccurrence)) {
                firstOccurrence[char] = i;
            }

            // Track position in the original string
            vowelIndices.push(i);
        }
    }

    // Get unique vowels present in s
    const uniqueVowels = Object.keys(counts);

    // Step 2: Sorting Vowel Types
    // Sort criteria:
    // 1. Frequency (Non-increasing / Descending)
    // 2. First Appearance Index (Ascending)
    uniqueVowels.sort((v1, v2) => {
        const freq1 = counts[v1];
        const freq2 = counts[v2];

        // Primary sort: Frequency descending
        if (freq1 !== freq2) {
            return freq2 - freq1;
        }

        // Secondary sort: First appearance index ascending
        const first1 = firstOccurrence[v1];
        const first2 = firstOccurrence[v2];
        return first1 - first2;
    });

    // Construct the final sequence of vowels to be inserted
    const replacementSequence = [];
    for (const vowel of uniqueVowels) {
        const count = counts[vowel];
        for (let i = 0; i < count; i++) {
            replacementSequence.push(vowel);
        }
    }

    // Step 3: Reconstruction
    const resultChars = s.split('');

    // Replace the vowels at the stored indices using the sorted sequence
    for (let k = 0; k < vowelIndices.length; k++) {
        const indexToReplace = vowelIndices[k];
        const replacementChar = replacementSequence[k];
        resultChars[indexToReplace] = replacementChar;
    }

    return resultChars.join('');
}

